const WebmVideo = ({ fallback, webmSrc, ...props }) => {
  const vidRef = createRef()
  const [canPlay, setCanPlay] = useState(true)
  useEffect(() => {
    if (vidRef.current === null) {
      return
    }
    if (vidRef?.current?.canPlayType('video/webm') === '') {
      setCanPlay(false)
    }
  }, [vidRef.current])
  return canPlay ? (
    <video {...props} ref={vidRef}>
      <source src={webmSrc} type="video/webm" />
    </video>
  ) : (
    fallback
  )
}
WebmVideo.propTypes = {
  fallback: PropTypes.node.isRequired,
  webmSrc: PropTypes.string.isRequired,
}
